const fs = require('fs');
const path = require('path');

module.exports = function (opts) {
  return async function (next) {
    const replaceCode = 'self.MonacoEnvironment.baseUrl+"/js/chunks';
    const bundleFile = path.resolve(__dirname, './build/js/bundle.js');
    let bundleText = fs.readFileSync(bundleFile, 'utf-8');
    bundleText = 'require("../css/bundle.css");' + bundleText
      .replace('o.p+"./js/chunks', replaceCode)
      .replace('__webpack_require__.p + "./js/chunks', replaceCode);
    fs.writeFileSync(bundleFile, bundleText);
    next();
  }
}; 